When('the user enters purchase intent', async function () {
  const data = this.contactDealerData?.[0] || {};
  const purchaseTime = data['Purchase Timeline'] || data['Purchase Time'] || data['When Purchase'] || '';
  // DOM-mapped: "When are you likely to purchase?" → #cad-page-purchase-time
  const dropdown = this.page.locator('#cad-page-purchase-time').first();
  if ((await dropdown.count()) > 0) {
    await dropdown.scrollIntoViewIfNeeded().catch(() => {});
    if (purchaseTime) {
      await dropdown.selectOption({ label: purchaseTime }).catch(async () => {
        const opts = await dropdown.locator('option').allTextContents();
        const match = opts.find(o => o.trim().toLowerCase().includes(purchaseTime.toLowerCase()));
        if (match) await dropdown.selectOption({ label: match.trim() }).catch(() => {});
      });
    }
    // Ensure a real option is selected (not a placeholder)
    const val = await dropdown.inputValue().catch(() => '');
    if (!val) {
      const options = await dropdown.locator('option').all();
      for (const opt of options) {
        const v = await opt.getAttribute('value');
        const t = (await opt.textContent() || '').trim();
        if (v && t && !/when|select|choose/i.test(t)) {
          await dropdown.selectOption({ value: v });
          break;
        }
      }
    }
    const finalVal = await dropdown.inputValue().catch(() => '');
    console.log(`📋 Selected purchase intent: "${finalVal}"`);
  } else {
    console.log('⚠️ Purchase time dropdown #cad-page-purchase-time not found');
  }
});

