When('the user submits the contact a dealer form', async function () {
  // Use the specific CAD form submit button (scoped to the form to avoid nav/search buttons)
  const submitBtn = this.page
    .locator('form button[type="submit"], .hyu-page-form button[type="submit"], .cad-form button[type="submit"], button[type="submit"]')
    .filter({ hasNotText: /search|find|go|cancel/i })
    .last();
  // Scroll into view first, then wait for visibility
  if ((await submitBtn.count()) > 0) {
    await submitBtn.scrollIntoViewIfNeeded({ timeout: 5000 }).catch(() => {});
    await this.page.waitForTimeout(500);
    // Wait up to 5s for it to become visible after scroll
    await submitBtn.waitFor({ state: 'visible', timeout: 5000 }).catch(() => {});
    if (await submitBtn.isVisible().catch(() => false)) {
      await submitBtn.evaluate(el => el.click()).catch(async () => {
        await submitBtn.click({ force: true }).catch(() => {});
      });
      console.log('📋 Clicked submit button');
    } else {
      // Force-click even if not fully visible (may be clipped by overflow)
      await submitBtn.click({ force: true }).catch(() => {});
      console.log('📋 Force-clicked submit button (not fully visible)');
    }
  } else {
    console.log('⚠️ No submit button found — using keyboard submit');
    await this.page.keyboard.press('Enter');
  }
  // Wait for the network to settle so the API response is captured before assertions run.
  // Try networkidle first (up to 15s), then fall back to a fixed 8s wait.
  await this.page.waitForLoadState('networkidle', { timeout: 15000 }).catch(async () => {
    console.log('ℹ️  networkidle not reached — waiting 8s for API response');
    await this.page.waitForTimeout(8000);
  });
  // Give the CDP hook an extra moment to flush the last captured payload
  await this.page.waitForTimeout(1500);
  // The CAD form shows "We are processing your request..." while the API is still in-flight.
  // Wait up to 20s for that text to disappear before moving on.
  const _processingStart = Date.now();
  while (Date.now() - _processingStart < 20000) {
    const _processing = await this.page.evaluate(() =>
      (document.body.innerText || '').toLowerCase().includes('processing your request')
    ).catch(() => false);
    if (!_processing) break;
    await this.page.waitForTimeout(1000);
  }
  // Extra settle time after processing spinner disappears
  await this.page.waitForTimeout(1000);
  console.log(`📋 Submit settled. Captured API payloads: ${this._capturedApiPayloads?.length || 0}`);
});

Then('the form should be submitted successfully', async function () {
  // Multi-signal success check (mirrors contact_us / talk-to-an-expert):
  //   1) visible thank-you / success / confirm element
  //   2) success-bearing URL (thank-you, success, confirm, complete)
  //   3) confirmation copy on the page
  //   4) a 2xx form-submission API response captured by the network listener
  // Wait up to 15s for any signal to appear — the CAD form sometimes redraws slowly
  // after the API resolves.
  const _start = Date.now();
  let visible = false, urlOk = false, textOk = false, apiOk = false;
  while (Date.now() - _start < 15000) {
    const _success = this.page.locator(
      '[class*="thank" i], [class*="success" i], [class*="confirm" i], [class*="all-done" i], [class*="complete" i]'
    ).first();
    visible = (await _success.count()) > 0 && (await _success.isVisible().catch(() => false));
    const _url = this.page.url();
    urlOk = /thank|success|confirm|complete/i.test(_url);
    textOk = await this.page.getByText(
      /thank you|thank-you|we.?ll be in touch|received your enquiry|enquiry submitted|submitted successfully|we have received|your enquiry has been sent/i
    ).first().isVisible().catch(() => false);
    // Form-submission endpoints (filter out tracking pixels)
    const _trackingDomains = /google|analytics|doubleclick|snapchat|linkedin|twitter|insight|marketo|mktoresp|facebook|gtag|pixel|hotjar|clarity|webevents/i;
    const _formPathPattern = /content\/api|\/api\/|\/form\/|\/submit|\/enquir|\/lead|\/contact-?a-?dealer|\/customer/i;
    apiOk = Array.isArray(this._capturedApiPayloads) && this._capturedApiPayloads.some(p =>
      (p.method === 'POST' || p.method === 'PUT') &&
      p.status >= 200 && p.status < 300 &&
      !_trackingDomains.test(p.url || '') &&
      _formPathPattern.test(p.url || '')
    );
    if (visible || urlOk || textOk || apiOk) break;
    await this.page.waitForTimeout(500);
  }
  console.log(`📋 CAD success check — visibleEl=${visible} urlOk=${urlOk} textOk=${textOk} apiOk=${apiOk}`);
  this.successMessage = { displayed: visible || textOk };
  assert.ok(visible || urlOk || textOk || apiOk, 'the form should be submitted successfully');
});

