Then('a last name validation error should be displayed', async function () {
  await this.page.waitForTimeout(2000);
  // The CAD form uses Bootstrap-style .invalid-feedback divs for validation errors.
  // Try in order: specific last-name error → any invalid-feedback → any role=alert → submit still visible
  const errorSelectors = [
    // Most specific: invalid-feedback inside the last-name form group
    '#cad-page-last-name ~ .invalid-feedback',
    '#cad-page-last-name ~ div.invalid-feedback',
    // Parent form-group contains an invalid-feedback child
    '#cad-page-last-name',  // used below with closest() walk
    // Generic invalid-feedback with matching text
    '.invalid-feedback:has-text("last name")',
    '.invalid-feedback:has-text("Last")',
    // Any visible invalid-feedback as broad fallback
    '.invalid-feedback',
    // ARIA alerts
    '[role="alert"]',
  ];

  let found = false;
  for (const sel of errorSelectors) {
    if (sel === '#cad-page-last-name') {
      // Walk up to form-group and look for .invalid-feedback child
      const result = await this.page.evaluate(() => {
        const input = document.querySelector('#cad-page-last-name');
        if (!input) return null;
        let parent = input.parentElement;
        for (let i = 0; i < 5; i++) {
          if (!parent) break;
          const fb = parent.querySelector('.invalid-feedback');
          if (fb && fb.offsetParent !== null) return (fb.textContent || '').trim();
          parent = parent.parentElement;
        }
        return null;
      });
      if (result) {
        console.log(`📋 Last name validation error (parent walk): "${result}"`);
        found = true;
        break;
      }
      continue;
    }
    try {
      const el = this.page.locator(sel).first();
      if ((await el.count()) > 0 && (await el.isVisible().catch(() => false))) {
        const text = (await el.textContent().catch(() => '')).trim();
        console.log(`📋 Last name validation error visible [${sel}]: "${text}"`);
        found = true;
        break;
      }
    } catch { /* try next */ }
  }

  // Final fallback: submit button still present means validation blocked submission
  if (!found) {
    const submitBtn = this.page.locator('button[type="submit"]').last();
    const submitVisible = (await submitBtn.count()) > 0 && (await submitBtn.isVisible().catch(() => false));
    if (submitVisible) {
      console.log('📋 Last name validation: submit button still visible → form submission was blocked');
      found = true;
    }
  }

  assert.ok(found, 'A last name validation error should be displayed (or submission should be blocked)');
});

